  7→  ScrollView,
  8→  StyleSheet,
  9→  Text,
 10→  TextInput,
 11→  useWindowDimensions,
 12→  View,
 13→} from 'react-native';
 14→import {useMutation, useQuery} from '@tanstack/react-query';
 15→import {NativeStackScreenProps} from '@react-navigation/native-stack';
 16→import {SafeAreaView} from 'react-native-safe-area-context';
 17→import {Avatar} from '../../components/Avatar';
 18→import {BadgeCheckIcon, RepostIcon, XIcon} from '../../components/icons';
 19→import {CommentThread, formatRelativeDate} from '../../components/Comments';
 20→import {ActionBar} from '../../components/PostCard/ActionBar';
 21→import {PrimaryButton} from '../../components/PrimaryButton';
 22→import {SkeletonLoader} from '../../components/SkeletonLoader';
 23→import {CanvasPreview} from '../../components/CanvasPreview/CanvasPreview';
 24→import {LexicalRenderer} from '../../lib/content/LexicalRenderer';
 25→import {RelatedPosts} from '../../components/Discovery/RelatedPosts';
 26→import {useAuth} from '../../features/auth/AuthProvider';
 27→import {useTheme} from '../../theme/ThemeProvider';
 28→import {useComments} from '../../hooks/useComments';
 29→import {fonts, typeScale} from '../../theme/typography';
 30→import {spacing, radii} from '../../theme/spacing';
 31→import {mobileApi} from '../../lib/api/mobileApi';
 32→import {socialApi} from '../../lib/api/socialApi';
 33→import {queryClient} from '../../lib/queryClient';
 34→import {extractPlainText, parseCanvasDoc} from '../../lib/utils/journalHelpers';
 35→import type {RootStackParamList} from '../../navigation/types';
 36→
 37→type Props = NativeStackScreenProps<RootStackParamList, 'PostDetail'>;
 38→
 39→const toCount = (value: unknown): number | null => {
 40→  const parsed = Number(value);
 41→  return Number.isFinite(parsed) && parsed >= 0 ? parsed : null;
 42→};
 43→
 44→const resolveCount = (
 45→  aggregate: Array<{count?: number}> | undefined,
 46→  fallback?: number,
 47→): number => {
 48→  return toCount(aggregate?.[0]?.count) ?? toCount(fallback) ?? 0;
 49→};
 50→
 51→const extractBannerImage = (content: string | null | undefined): string | null => {
 52→  if (!content) return null;
 53→  try {
 54→    const parsed = JSON.parse(content);
 55→    const findImage = (node: any): string | null => {
 56→      if (node.type === 'image' && node.src) return node.src;
 57→      if (node.children) {
 58→        for (const child of node.children) {
 59→          const found = findImage(child);
 60→          if (found) return found;
 61→        }
 62→      }
 63→      return null;
 64→    };
 65→    return findImage(parsed.root ?? parsed);
 66→  } catch {
 67→    return null;
 68→  }
 69→};
 70→
 71→export function PostDetailScreen({route, navigation}: Props) {
 72→  const {user, session} = useAuth();
 73→  const {colors} = useTheme();
 74→  const {width: windowWidth} = useWindowDimensions();
 75→  const {journalId} = route.params;
 76→  const token = session?.access_token ?? '';
 77→  const [repostCaption, setRepostCaption] = useState('');
 78→  const [showRepost, setShowRepost] = useState(false);
 79→  const scrollViewRef = useRef<ScrollView>(null);
 80→  const inputRef = useRef<TextInput>(null);
 81→
 82→  const onReplyActivated = useCallback(() => {
 83→    setTimeout(() => {
 84→      inputRef.current?.focus();
 85→      scrollViewRef.current?.scrollToEnd({animated: true});
 86→    }, 100);
 87→  }, []);
 88→
 89→  const detailQuery = useQuery({
 90→    queryKey: ['journal', journalId, user?.id],
 91→    queryFn: () => mobileApi.getJournalById(journalId, user?.id),
 92→  });
 93→
 94→  const receiverId = (detailQuery.data?.journal?.user_id ?? detailQuery.data?.journal?.users?.id) || undefined;
 95→
 96→  const {
 97→    comments,
 98→    isLoading: commentsLoading,
 99→    commentInput,
100→    setCommentInput,
101→    replyingTo,
102→    setReplyingTo,
103→    expandedReplies,
104→    fetchedReplies,
105→    loadingReplies,
106→    handleReply,
107→    handleToggleReplies,
108→    submitComment,
109→    isSubmitting,
110→  } = useComments(journalId, receiverId, token, onReplyActivated);
111→
112→  const reactionMutation = useMutation({
113→    mutationFn: async (reactionType: string) => {
114→      const journal = detailQuery.data?.journal;
115→      const rid = journal?.user_id ?? journal?.users?.id;
116→      if (!token) throw new Error('Please log in to react.');
117→      if (!journal?.id || !rid) throw new Error('Missing journal data.');
118→      return socialApi.toggleReaction(token, {
119→        journalId: journal.id,
120→        receiverId: rid,
121→        reactionType,
122→      });
123→    },
124→    onSuccess: () => {
125→      queryClient.invalidateQueries({queryKey: ['journal', journalId]});
126→      queryClient.invalidateQueries({queryKey: ['feed']});
127→    },
128→    onError: e => Alert.alert('Reaction failed', e instanceof Error ? e.message : 'Error'),
129→  });
130→
131→  const bookmarkMutation = useMutation({
132→    mutationFn: async () => {
133→      if (!token) throw new Error('Please log in to bookmark.');
134→      return socialApi.toggleBookmark(token, {journalId});
135→    },
136→    onSuccess: () => {
137→      queryClient.invalidateQueries({queryKey: ['journal', journalId]});
138→      queryClient.invalidateQueries({queryKey: ['feed']});
139→    },
140→    onError: e => Alert.alert('Bookmark failed', e instanceof Error ? e.message : 'Error'),
141→  });
142→
143→  const repostMutation = useMutation({
144→    mutationFn: async () => {
145→      if (!token) throw new Error('Please log in to repost.');
146→      return socialApi.createRepost(token, {
147→        sourceJournalId: journalId,
148→        caption: repostCaption.trim() || undefined,
149→      });
150→    },
151→    onSuccess: () => {
152→      setRepostCaption('');
153→      setShowRepost(false);
154→      Alert.alert('Reposted', 'Post was reposted to your feed.');
155→      queryClient.invalidateQueries({queryKey: ['feed']});
156→    },
157→    onError: e => Alert.alert('Repost failed', e instanceof Error ? e.message : 'Error'),
158→  });
159→
160→  const journal = detailQuery.data?.journal;
161→  const likeCount = resolveCount(journal?.like_count, journal?.likes_count);
162→  const commentCount = resolveCount(journal?.comment_count, journal?.comments_count);
163→  const bookmarkCount = resolveCount(journal?.bookmark_count);
164→  const bannerImage = useMemo(() => extractBannerImage(journal?.content), [journal?.content]);
165→  const isRepost = !!journal?.is_repost;
166→  const canvasDoc = parseCanvasDoc(journal?.canvas_doc);
167→  const isCanvas = !!(canvasDoc?.snippets?.length || canvasDoc?.images?.length || canvasDoc?.doodles?.length);
168→  const repostSource = isRepost ? journal?.repost_source : null;
169→  const repostSourcePreview = repostSource?.content
170→    ? extractPlainText(repostSource.content).slice(0, 200)
171→    : '';
172→
173→  if (detailQuery.isLoading) {
174→    return (
175→      <SafeAreaView style={[styles.safe, {backgroundColor: colors.bgPrimary}]}>
176→        <View style={styles.loadingContainer}>
177→          <SkeletonLoader height={200} borderRadius={0} />
178→          <View style={styles.contentPadding}>
179→            <SkeletonLoader width="70%" height={24} />
180→            <SkeletonLoader width="40%" height={16} style={{marginTop: 12}} />
181→            <SkeletonLoader width="100%" height={16} style={{marginTop: 20}} />
182→            <SkeletonLoader width="100%" height={16} style={{marginTop: 8}} />
183→            <SkeletonLoader width="60%" height={16} style={{marginTop: 8}} />
184→          </View>
185→        </View>
186→      </SafeAreaView>
187→    );
188→  }
189→
190→  if (detailQuery.isError) {
191→    return (
192→      <SafeAreaView style={[styles.safe, {backgroundColor: colors.bgPrimary}]}>
193→        <View style={styles.contentPadding}>
194→          <Text style={[styles.errorText, {color: colors.danger}]}>
195→            Unable to load this post.
196→          </Text>
197→        </View>
198→      </SafeAreaView>
199→    );
200→  }
201→
202→  return (
203→    <ScrollView
204→      ref={scrollViewRef}
205→      style={[styles.scroll, {backgroundColor: colors.bgPrimary}]}
206→      showsVerticalScrollIndicator={false}>
207→      {/* Banner image / Canvas preview */}
208→      {!isRepost && isCanvas ? (
209→        <CanvasPreview canvasDoc={journal?.canvas_doc ?? null} width={windowWidth} />
210→      ) : !isRepost && bannerImage ? (
211→        <Image source={{uri: bannerImage}} style={styles.banner} resizeMode="cover" />
212→      ) : null}
213→
214→      <View style={styles.contentPadding}>
215→        {/* Title / Repost badge */}
216→        {isRepost ? (
217→          <View style={styles.repostBadge}>
218→            <RepostIcon size={14} color={colors.textFaint} />
219→            <Text style={[styles.repostBadgeText, {color: colors.textFaint}]}>
220→              <Text style={[styles.repostBadgeName, {color: colors.textSecondary}]}>
221→                {journal?.users?.name || 'Someone'}
222→              </Text>
223→              {' reposted'}
224→            </Text>
225→          </View>
226→        ) : (
227→          <Text style={[styles.title, {color: colors.textHeading}]}>
228→            {journal?.title || 'Untitled Post'}
229→          </Text>
230→        )}
231→
232→        {/* Author section */}
233→        <Pressable
234→          style={styles.authorRow}
235→          onPress={() => {
236→            const authorId = journal?.users?.id ?? journal?.user_id;
237→            if (!authorId) return;
