252→          />
253→          <View style={styles.authorInfo}>
254→            <View style={styles.authorNameRow}>
255→              <Text style={[styles.authorName, {color: colors.textPrimary}]}>
256→                {journal?.users?.name || 'Unknown author'}
257→              </Text>
258→              {journal?.users?.badge ? (
