260→              ) : null}
261→            </View>
262→            <Text style={[styles.dateText, {color: colors.textMuted}]}>
263→              {formatRelativeDate(journal?.created_at)}
264→            </Text>
265→          </View>
266→        </Pressable>
267→
268→        {/* Repost caption */}
269→        {isRepost && journal?.repost_caption ? (
270→          <Text style={[styles.repostCaptionText, {color: colors.textPrimary}]}>
271→            {journal.repost_caption}
272→          </Text>
273→        ) : null}
274→
275→        {/* Action bar */}
276→        <ActionBar
277→          likeCount={likeCount}
278→          commentCount={commentCount}
279→          bookmarkCount={bookmarkCount}
280→          isLiked={journal?.has_liked}
281→          isBookmarked={journal?.has_bookmarked}
282→          userReaction={journal?.user_reaction}
283→          onReact={type => reactionMutation.mutate(type)}
284→          onComment={() => {/* scroll to comments */}}
285→          onBookmark={() => bookmarkMutation.mutate()}
286→          onRepost={() => setShowRepost(!showRepost)}
287→        />
288→
289→        {/* Repost section */}
290→        {showRepost && (
291→          <View style={[styles.repostSection, {backgroundColor: colors.bgSecondary, borderColor: colors.borderLight}]}>
292→            <TextInput
293→              value={repostCaption}
294→              onChangeText={setRepostCaption}
295→              placeholder="Add an optional caption"
296→              placeholderTextColor={colors.textFaint}
297→              style={[styles.commentInput, {backgroundColor: colors.bgElevated, borderColor: colors.borderCard, color: colors.textPrimary}]}
298→              maxLength={280}
