303→              onPress={() => repostMutation.mutate()}
304→              disabled={repostMutation.isPending}
305→            />
306→          </View>
307→        )}
308→
309→        {/* Divider */}
310→        <View style={[styles.divider, {backgroundColor: colors.borderLight}]} />
311→
312→        {/* Content body / Embedded original post */}
313→        {isRepost ? (
