353→
354→        {/* Divider */}
355→        <View style={[styles.divider, {backgroundColor: colors.borderLight}]} />
356→
357→        {/* Comments section */}
358→        <Text style={[styles.sectionTitle, {color: colors.textHeading}]}>
359→          Comments ({commentCount})
360→        </Text>
361→
362→        {commentsLoading ? (
363→          <View style={styles.commentLoading}>
364→            <ActivityIndicator color={colors.loaderColor} />
365→          </View>
366→        ) : comments.filter(c => !c.parent_id).length === 0 ? (
367→          <Text style={[styles.noComments, {color: colors.textMuted}]}>
