                <Text style={[styles.embeddedAuthorName, {color: colors.textPrimary}]}>
                  {repostSource.users?.name || 'Unknown author'}
                </Text>
              </View>
              {repostSource.title ? (
                <Text style={[styles.embeddedTitle, {color: colors.textHeading}]}>
