 97→export const mobileApi = {
 98→  async getJournals(cursor: string | null, limit = 10, userId?: string): Promise<CursorPage<JournalItem>> {
 99→    const params = new URLSearchParams();
100→    params.set('limit', String(limit));
101→    if (cursor) {
102→      params.set('before', cursor);
103→    }
104→    if (userId) {
105→      params.set('userId', userId);
106→    }
107→
108→    return apiRequest<CursorPage<JournalItem>>(`/journals?${params.toString()}`, {
109→      method: 'GET',
110→    });
111→  },
112→
113→  async getJournalById(journalId: string, userId?: string): Promise<{ journal: JournalItem }> {
114→    const params = new URLSearchParams();
115→    if (userId) {
116→      params.set('userId', userId);
117→    }
118→
119→    const suffix = params.toString() ? `?${params.toString()}` : '';
120→    return apiRequest<{ journal: JournalItem }>(`/journal/${encodeURIComponent(journalId)}${suffix}`, {
121→      method: 'GET',
122→    });
123→  },
124→
125→  async searchUsers(query: string, limit = 20): Promise<{ data: UserPreview[]; hasMore: boolean }> {
126→    const params = new URLSearchParams();
127→    params.set('query', query.trim());
128→    params.set('limit', String(limit));
129→
130→    return apiRequest<{ data: UserPreview[]; hasMore: boolean }>(`/users/search?${params.toString()}`, {
131→      method: 'GET',
132→    });
133→  },
