.search-shell{
    position: sticky;
    top: 0;
    z-index: 14;
    align-self: stretch;
    width: 100%;
    max-width: 100%;
}
.search-top-bar{
    position: relative;
    z-index: 12;
    display: flex;
    align-items: center;
    gap: 0.5rem;
    width: 100%;
    padding: 0.65rem 0.75rem 0.75rem 0.75rem;
    box-sizing: border-box;
    background: var(--bg-primary);
    border-bottom: 1px solid var(--border-card);
}
.search-input-wrap{
    position: relative;
    display: flex;
    align-items: center;
    flex: 1;
}
.search-icon{
    position: absolute;
    left: 0.85rem;
    width: 15px;
    height: 15px;
    color: var(--text-faint);
    pointer-events: none;
    transition: color 0.25s ease, transform 0.25s ease;
}
.search-input-wrap:focus-within .search-icon{
    color: #D4A853;
    transform: scale(1.08);
}
.search-input{
    width: 100%;
    border: 1.5px solid var(--border-card);
    border-radius: 10px;
    padding: 0.6rem 0.9rem 0.6rem 2.4rem;
    font-family: var(--font-ui);
    font-size: 0.84rem;
    font-weight: 450;
    letter-spacing: 0.01rem;
    color: var(--text-heading);
    background: var(--bg-secondary);
    outline: none;
    transition: border-color 0.3s ease, box-shadow 0.3s ease, background 0.3s ease;
}
.search-input::placeholder{
    color: var(--text-faint);
    font-weight: 400;
    letter-spacing: 0.015rem;
}
.search-input:focus{
    border-color: #D4A853;
    background: var(--bg-card);
    box-shadow:
        0 0 0 3px rgba(212, 168, 83, 0.1),
        0 2px 8px rgba(212, 168, 83, 0.06);
}
.search-clear-btn{
    border: 1.5px solid var(--border-card);
    background: var(--bg-secondary);
    color: var(--text-secondary);
    border-radius: 8px;
    font-family: var(--font-ui);
    font-size: 0.7rem;
    font-weight: 600;
    letter-spacing: 0.02rem;
    padding: 0.4rem 0.72rem;
    cursor: pointer;
    transition: background 0.2s ease, border-color 0.2s ease, color 0.2s ease;
    white-space: nowrap;
}
.search-clear-btn:hover{
    background: var(--bg-hover);
    border-color: #D4A853;
    color: #D4A853;
}
/* ── Nav row (Stories) ── */
.search-nav-row{
    display: flex;
    gap: 6px;
    padding: 0.4rem 0.75rem;
}
.search-nav-btn{
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 0.35rem;
    flex: 1;
    border-radius: 999px;
    font-family: var(--font-ui);
    font-size: 0.74rem;
    font-weight: 700;
    letter-spacing: 0.01rem;
--
    .search-shell{
        top: 0;
        position: relative;
    }
    .search-top-bar{
        padding: 0.5rem 0.5rem 0.55rem 0.5rem;
        gap: 0.4rem;
    }
    .search-input{
        font-size: 0.8rem;
        padding: 0.5rem 0.75rem 0.5rem 2.1rem;
        border-radius: 8px;
    }
    .search-icon{
        left: 0.7rem;
        width: 14px;
        height: 14px;
    }

.search-suggestions-dropdown{
    position: absolute;
    left: 0.75rem;
    right: 0.75rem;
    top: calc(100% - 0.15rem);
    z-index: 30;
    border: 1.5px solid var(--border-card);
    border-radius: 10px;
    background: var(--bg-elevated);
    box-shadow:
        0 8px 24px rgba(0, 0, 0, 0.1),
        0 2px 8px rgba(0, 0, 0, 0.06);
    max-height: 320px;
    overflow-y: auto;
    padding: 0.3rem 0;
    animation: searchDropdownIn 0.2s ease-out;
}
@keyframes searchDropdownIn{
    from{
        opacity: 0;
        transform: translateY(-6px);
    }
    to{
        opacity: 1;
        transform: translateY(0);
    }
}
.search-suggestion-item{
    width: 100%;
    text-align: left;
    border: none;
    background: transparent;
    cursor: pointer;
    display: flex;
    flex-direction: column;
    gap: 0.15rem;
    padding: 0.6rem 0.85rem;
    transition: background 0.15s ease;
    border-left: 2.5px solid transparent;
}
.search-suggestion-item:hover{
    background: var(--bg-pill);
    border-left-color: #D4A853;
}
.search-suggestion-title{
    font-family: var(--font-ui);
    font-size: 0.8rem;
    font-weight: 600;
    color: var(--text-heading);
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}
.search-suggestion-meta{
    font-family: var(--font-ui);
    font-size: 0.68rem;
    font-weight: 450;
    color: var(--text-faint);
    letter-spacing: 0.01rem;
