1296→        userMap.set(user.id, user);
1297→    });
1298→    (usernameResult.data || []).forEach((user) => {
1299→        if(!userMap.has(user.id)){
1300→            userMap.set(user.id, user);
1301→        }
1302→    });
1303→
1304→    const users = [...userMap.values()];
1305→    const hasMore = users.length > parsedLimit;
1306→
1307→    return {
1308→        data: hasMore ? users.slice(0, parsedLimit) : users,
1309→        hasMore: hasMore
1310→    };
1311→}
1312→
1313→export const searchJournalsService = async(query, limit, userId) => {
1314→    const normalizedQuery = normalizeSearchQuery(query);
1315→    if(!normalizedQuery || normalizedQuery.length < SEARCH_QUERY_MIN_LENGTH){
1316→        throw {status: 400, error: `query should be at least ${SEARCH_QUERY_MIN_LENGTH} characters`};
1317→    }
1318→
1319→    if(isNaN(limit) || limit < 1 || limit > SEARCH_LIMIT_MAX){
1320→        throw {status: 400, error: `limit should be an integer between 1 and ${SEARCH_LIMIT_MAX}`};
1321→    }
1322→
1323→    const parsedLimit = parseInt(limit);
1324→    const fetchLimit = Math.min(parsedLimit * 3, 60);
1325→
1326→    const selectColumns = JOURNAL_WITH_COUNTS_SELECT;
1327→
1328→    // Prefer semantic retrieval. If pgvector RPC is unavailable or errors,
1329→    // fallback to keyword search so endpoint still returns useful data.
1330→    try {
1331→        const queryEmbedding = await GenerateEmbeddings(normalizedQuery, '');
1332→
1333→        if(Array.isArray(queryEmbedding) && queryEmbedding.length > 0){
1334→            const {data: matches, error: matchError} = await supabase.rpc('match_public_journals', {
1335→                query_embedding: queryEmbedding,
1336→                match_count: fetchLimit,
1337→                similarity_threshold: 0.35
1338→            });
1339→
1340→            if(matchError){
1341→                console.error('semantic search rpc error:', matchError.message);
1342→            } else if(Array.isArray(matches) && matches.length > 0){
1343→                const matchIds = matches.map((row) => row.id);
1344→                const similarityMap = new Map(matches.map((row) => [row.id, row.similarity]));
1345→
1346→                const {data: journals, error: errorJournals} = await supabase
1347→                    .from('journals')
1348→                    .select(selectColumns)
1349→                    .in('id', matchIds)
1350→                    .eq('privacy', 'public');
1351→
1352→                if(errorJournals){
1353→                    console.error('supabase error while fetching semantic search journals:', errorJournals.message);
1354→                    throw {status: 500, error: 'supabase error while fetching semantic search journals'};
1355→                }
1356→
1357→                const journalById = new Map((journals || []).map((journal) => [journal.id, journal]));
1358→                const orderedSemantic = matchIds
1359→                    .map((id) => journalById.get(id))
1360→                    .filter(Boolean)
1361→                    .map((journal) => ({
1362→                        ...journal,
1363→                        similarity: similarityMap.get(journal.id) || null
1364→                    }));
1365→
1366→                const withInteraction = await attachUserInteractionFlags(orderedSemantic, userId);
1367→                const hasMore = withInteraction.length > parsedLimit;
1368→
1369→                return {
1370→                    data: hasMore ? withInteraction.slice(0, parsedLimit) : withInteraction,
1371→                    hasMore: hasMore,
1372→                    mode: 'semantic'
1373→                };
1374→            }
1375→        }
1376→    } catch (error) {
1377→        console.error('semantic embedding/search fallback error:', error?.message || error);
1378→    }
1379→
1380→    const escapedQuery = normalizedQuery.replace(/[%_]/g, (match) => `\\${match}`);
1381→
1382→    const [titleResult, contentResult] = await Promise.all([
1383→        supabase
1384→            .from('journals')
1385→            .select(selectColumns)
1386→            .eq('privacy', 'public')
1387→            .ilike('title', `%${escapedQuery}%`)
1388→            .order('created_at', {ascending: false})
1389→            .order('id', {ascending: false})
1390→            .limit(parsedLimit + 1),
1391→        supabase
1392→            .from('journals')
1393→            .select(selectColumns)
1394→            .eq('privacy', 'public')
1395→            .ilike('content', `%${escapedQuery}%`)
1396→            .order('created_at', {ascending: false})
1397→            .order('id', {ascending: false})
1398→            .limit(parsedLimit + 1)
1399→    ]);
1400→
1401→    if(titleResult.error || contentResult.error){
1402→        console.error('keyword search error:', titleResult.error?.message || contentResult.error?.message);
1403→        throw {status: 500, error: 'supabase error while searching journals'};
1404→    }
1405→
1406→    const keywordMap = new Map();
1407→    (titleResult.data || []).forEach((journal) => {
1408→        keywordMap.set(journal.id, journal);
1409→    });
1410→    (contentResult.data || []).forEach((journal) => {
1411→        if(!keywordMap.has(journal.id)){
1412→            keywordMap.set(journal.id, journal);
1413→        }
1414→    });
1415→
1416→    const keywordJournals = [...keywordMap.values()];
1417→
1418→    const withInteraction = await attachUserInteractionFlags(keywordJournals || [], userId);
1419→    const hasMore = withInteraction.length > parsedLimit;
1420→
1421→    return {
1422→        data: hasMore ? withInteraction.slice(0, parsedLimit) : withInteraction,
1423→        hasMore: hasMore,
1424→        mode: 'keyword'
1425→    };
1426→}
